#include <bits/stdc++.h>
using namespace std;
const int INF=0x3f3f3f3f+1;
double d_1,c,d_2,d[10],p[10],num=0,sum;
int n;
int main()
{
	cin>>d_1>>c>>d_2>>p[0]>>n;
	d[0]=0;
	for(int i=1;i<=n;i++)
	{
		cin>>d[i]>>p[i]; 
	}
	d[n+1]=d_1;
	p[n+1]=INF;
	for(int i=0;i<=n;)
	{
		double t=c*d_2,mn=0x3f3f3f3f+10;
		int id;
		for(int j=i+1;d[j]<=t+d[i];j++)
		{
			if(mn>p[j])
			{
				mn=p[j];
				id=j;
			}
			if(j==n+1) break;
		}
		if(mn==0x3f3f3f3f)
		{
			cout<<"No Solution";
			return 0;
		}
		if(mn<p[i]||mn==INF)
		{
			double need=(d[id]-d[i])/d_2;
			if(num>=need)
			{
				i=id;
				num-=need;
				continue;
			}
			sum+=((need-num)*p[i]);
			num=0;
			i=id;
			continue;
		}
		sum+=(c-num)*p[i];
		num=c-(d[id]-d[i])/d_2;
		i=id;
	}
	cout<<fixed<<setprecision(2)<<sum;
	return 0;
}
